import java.util.Scanner;

public class SecureCommandExecution {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a command to execute: ");
        String command = scanner.nextLine();

        if (!isValidCommand(command)) {
            System.out.println("Invalid command. Please try again.");
            return;
        }

        try {
            Process process = Runtime.getRuntime().exec(command);
            // Process the output of the command here
        } catch (IOException e) {
            System.out.println("Error executing command: " + e.getMessage());
        }
    }

    private static boolean isValidCommand(String command) {
        // Add your validation logic here
        // For example, allow only specific commands or patterns
        return command.matches("[a-zA-Z0-9_-]+");
